# Lookup dict for quick access
DISH_LOOKUP = {d["name"].lower(): d for d in MASTER_DISHES}

def get_dish(name: str) -> dict | None:
    """Case-insensitive dish lookup."""
    return DISH_LOOKUP.get(name.lower().strip())

def get_all_names() -> list[str]:
    return [d["name"] for d in MASTER_DISHES]
